    75→int nfp_flower_cmsg_portmod(struct nfp_repr *repr, bool carrier_ok,
    76→			    unsigned int mtu, bool mtu_only)
    77→{
    78→	struct nfp_flower_cmsg_portmod *msg;
    79→	struct sk_buff *skb;
